    public class RegularExpressionMatch : Block
    {
        public override async Task ExecuteAsync(List<object> inputs, ProgramStructure programStructure, string sessionId, Guid variableid)
        {
            var match = Regex.Match(inputs[0].ToString(), inputs[1].ToString());
            var matchResult = match.Success;
            var matchedGroups = match.Groups.Cast<Group>().Select(g => g.Value).ToList();
            programStructure.InputValues[Outputs[0].Id] = matchResult;
            programStructure.InputValues[Outputs[1].Id] = matchedGroups;
        }
    }

    public class Format : Block
    {
        public override async Task ExecuteAsync(List<object> inputs, ProgramStructure programStructure, string sessionId, Guid variableid)
        {
            var args = ((List<object>)inputs[1]).ToArray();
            var formattedString = string.Format(inputs[0].ToString(), args);
            programStructure.InputValues[Outputs[0].Id] = formattedString;
        }
    }

    public class StringCleaner : Block
    {
        public override async Task ExecuteAsync(List<object> inputs, ProgramStructure programStructure, string sessionId, Guid variableId)
        {
            var mainString = inputs[0].ToString();
            var startDelimiter = inputs[1].ToString();
            var endDelimiter = inputs[2].ToString();

            var cleanedString = RemoveSubstringsBetweenDelimiters(mainString, startDelimiter, endDelimiter);

            programStructure.InputValues[Outputs[0].Id] = cleanedString;
        }

        private string RemoveSubstringsBetweenDelimiters(string input, string start, string end)
        {
            var regexPattern = Regex.Escape(start) + "(.*?)" + Regex.Escape(end);
            return Regex.Replace(input, regexPattern, string.Empty);
        }
    }

    public class FindClosestStrings : Block
    {
        public override async Task ExecuteAsync(List<object> inputs, ProgramStructure programStructure, string sessionId, Guid variableId)
        {
            var stringList = inputs[0] as List<string>;
            var searchString = inputs[1].ToString();
            var number = Convert.ToInt32(inputs[2]);

            // Remove stopwords from searchString
            searchString = RemoveStopwords(searchString);

            // Logic to find closest strings or sentences
            var closestStrings = FindClosest(stringList, searchString, number);

            programStructure.InputValues[Outputs[0].Id] = closestStrings;
        }

        private List<string> FindClosest(List<string> stringList, string searchString, int number)
        {
            return stringList
                .Select(str => new { Str = str, Score = CalculateScore(str, searchString) })
                .OrderByDescending(pair => pair.Score)
                .Take(number)
                .Select(pair => pair.Str)
                .ToList();
        }

        private static int CalculateScore(string memory, string search)
        {
            // Break the memory and search strings into words
            var memoryWords = memory.Split(' ');
            var searchWords = search.Split(' ');

            // Calculate score based on word matches and Levenshtein Distance
            int score = 0;
            foreach (var searchWord in searchWords)
            {
                foreach (var memoryWord in memoryWords)
                {
                    // Adding condition to check for exact or close matches
                    if (searchWord.Equals(memoryWord, StringComparison.OrdinalIgnoreCase) ||
                        LevenshteinDistance(searchWord, memoryWord) <= 2) // Adjust threshold as needed
                    {
                        score++;
                    }
                }
            }

            return score;
        }

